import{_ as e,o as t,c as s,ao as i}from"./chunks/framework.D4X-SPNi.js";const u=JSON.parse('{"title":"Get started","description":"","frontmatter":{},"headers":[],"relativePath":"get-started.md","filePath":"get-started.md","lastUpdated":null}'),r={name:"get-started.md"};function n(l,a,o,h,d,p){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="Get-started" tabindex="-1">Get started <a class="header-anchor" href="#Get-started" aria-label="Permalink to &quot;Get started {#Get-started}&quot;">​</a></h1><p>This page takes you from nothing to your first tracked videos. You&#39;ll do three things: install Julia, install Fromage, and run your first analysis.</p><h2 id="1.-Install-Julia" tabindex="-1">1. Install Julia <a class="header-anchor" href="#1.-Install-Julia" aria-label="Permalink to &quot;1. Install Julia {#1.-Install-Julia}&quot;">​</a></h2><p>Fromage needs Julia <strong>1.11 or newer</strong>. Follow the instructions at <a href="https://julialang.org/downloads/" target="_blank" rel="noreferrer">julialang.org/downloads</a> — the recommended <code>juliaup</code> installer keeps Julia up to date for you.</p><div class="warning custom-block"><p class="custom-block-title">Using a Mac with an Apple Silicon chip (M1/M2/M3/…)?</p><p>Almost everything works, but the AprilTag features (drone tracking and <code>type = apriltag</code> calibrations) currently don&#39;t run natively on Apple Silicon. If you need those, install the <strong>Intel (x86_64) Julia binary</strong> and run it under Rosetta 2. Everything else — checkerboard calibrations and ordinary fixed-camera tracking — works natively. Details on the <a href="/Fromage.jl/previews/PR40/help#Macs">Help page</a>.</p></div><h2 id="2.-Install-Fromage" tabindex="-1">2. Install Fromage <a class="header-anchor" href="#2.-Install-Fromage" aria-label="Permalink to &quot;2. Install Fromage {#2.-Install-Fromage}&quot;">​</a></h2><p>Open Julia, type <code>]</code> to enter the package manager (the prompt changes to <code>pkg&gt;</code>), and run:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pkg&gt; add https://github.com/yakir12/Fromage.jl</span></span></code></pre></div><p>That&#39;s it — this installs Fromage and everything it needs. Press backspace to leave the package manager.</p><h2 id="3.-Run-your-first-analysis" tabindex="-1">3. Run your first analysis <a class="header-anchor" href="#3.-Run-your-first-analysis" aria-label="Permalink to &quot;3. Run your first analysis {#3.-Run-your-first-analysis}&quot;">​</a></h2><h3 id="Prepare-a-folder" tabindex="-1">Prepare a folder <a class="header-anchor" href="#Prepare-a-folder" aria-label="Permalink to &quot;Prepare a folder {#Prepare-a-folder}&quot;">​</a></h3><p>Put your video files together with two small spreadsheet files, <code>calibs.csv</code> and <code>runs.csv</code>, in one folder:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my experiment/</span></span>
<span class="line"><span>├── calibs.csv        ← one row per calibration video</span></span>
<span class="line"><span>├── runs.csv          ← one row per run video</span></span>
<span class="line"><span>├── calib_morning.mp4</span></span>
<span class="line"><span>├── beetle01.mp4</span></span>
<span class="line"><span>├── beetle02.mp4</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div><p>The two csv files are where you tell Fromage what to do — which video is which, when each run starts and stops, how big the target is, and so on. The <a href="./data-folder">data folder page</a> explains them, and template files to copy from live in <a href="https://github.com/yakir12/Fromage.jl/tree/main/examples" target="_blank" rel="noreferrer"><code>examples/</code></a>.</p><h3 id="Start-Julia-with-multiple-threads" tabindex="-1">Start Julia with multiple threads <a class="header-anchor" href="#Start-Julia-with-multiple-threads" aria-label="Permalink to &quot;Start Julia with multiple threads {#Start-Julia-with-multiple-threads}&quot;">​</a></h3><p>Tracking and calibrating are parallelized, and this makes a big difference. In your terminal:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --threads=auto</span></span></code></pre></div><h3 id="Run-it" tabindex="-1">Run it <a class="header-anchor" href="#Run-it" aria-label="Permalink to &quot;Run it {#Run-it}&quot;">​</a></h3><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Fromage</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">runs </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;the/path/to/your/data/folder&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p><code>main</code> then works through four stages: 2. <strong>Checks everything first.</strong> Every row of both csv files is validated: files exist and are readable videos, timestamps fall within each video&#39;s duration, the checkerboard is actually detectable, all parameters are within sane ranges. If <em>anything</em> is wrong, it prints one line per problematic row (e.g. <code>row 3: file does not exist, wrong start format</code>) and stops before any tracking starts — fix the csv files and run again. Nothing is half-done.</p><ol start="3"><li><p><strong>Builds a calibration</strong> for every run from its entry in <code>calibs.csv</code>.</p></li><li><p><strong>Tracks the target</strong> in every run.</p></li><li><p><strong>Writes your results</strong>: one track file per run plus a single diagnostic video, all in a <code>results_dir</code> folder (created where you started Julia).</p></li></ol><h3 id="Watch-the-diagnostic-video" tabindex="-1">Watch the diagnostic video <a class="header-anchor" href="#Watch-the-diagnostic-video" aria-label="Permalink to &quot;Watch the diagnostic video {#Watch-the-diagnostic-video}&quot;">​</a></h3><p>Open <code>results_dir/diagnostic.mp4</code> and watch it — it shows every run with a circle around the tracked position and a trailing trace. This is the fastest way to catch a tracker that latched onto a shadow or a wrong starting position. <strong>Always watch it before using the tracks.</strong></p><h2 id="Where-to-next?" tabindex="-1">Where to next? <a class="header-anchor" href="#Where-to-next?" aria-label="Permalink to &quot;Where to next? {#Where-to-next?}&quot;">​</a></h2><ul><li><p><a href="./data-folder">The data folder</a> — how to organise your files and the rules both csv files share.</p></li><li><p><a href="./runs">runs.csv</a> — describing your run videos.</p></li><li><p><a href="./calibs">calibs.csv</a> — describing your calibration videos.</p></li><li><p><a href="./results">Your results</a> — what the output files contain and how the coordinates work.</p></li><li><p><a href="./help">Help &amp; troubleshooting</a> — when something goes wrong.</p></li></ul>`,25)])])}const g=e(r,[["render",n]]);export{u as __pageData,g as default};
